import CoreImage
import SwiftUI
import UIKit

enum QRCodeGenerator {
    private static let context = CIContext()

    /// Generates a SwiftUI Image of a QR code for the given string.
    /// - Parameters:
    ///   - string: Content to encode (URL, text, etc.). Empty string returns a placeholder.
    ///   - size: Desired side length in points. Default 200.
    /// - Returns: SwiftUI Image of the QR code, or a small placeholder if generation fails.
    static func image(for string: String, size: CGFloat = 200) -> Image {
        guard !string.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              let filter = CIFilter(name: "CIQRCodeGenerator") else {
            return Image(systemName: "qrcode")
                .font(.system(size: size * 0.5))
                .foregroundStyle(.secondary)
        }
        filter.setValue(Data(string.utf8), forKey: "inputMessage")
        filter.setValue("H", forKey: "inputCorrectionLevel")
        guard let output = filter.outputImage else {
            return Image(systemName: "qrcode")
                .font(.system(size: size * 0.5))
                .foregroundStyle(.secondary)
        }
        let extent = output.extent
        let scale = size / extent.width
        let scaled = output.transformed(by: CGAffineTransform(scaleX: scale, y: scale))
        guard let cgImage = context.createCGImage(scaled, from: scaled.extent) else {
            return Image(systemName: "qrcode")
                .font(.system(size: size * 0.5))
                .foregroundStyle(.secondary)
        }
        return Image(uiImage: UIImage(cgImage: cgImage))
            .interpolation(.none)
            .resizable()
            .scaledToFit()
    }
}
